#include <iostream>
#include <fstream>
#include <string>

int main() {
  std::ofstream file;
  file.open("example.txt", std::ios::out);
  if(file.is_open()) {
    file << "Hello, World!\n";
    file.close();
  } else {
    std::cout << "Failed to open file\n";
  }
  return 0;
}
// Output: Creates a file named example.txt with content "Hello, World!"

#include <iostream>
#include <fstream>
#include <string>

int main() {
  std::ofstream file("example.txt", std::ios::out);
  if(file.is_open()) {
    file << "Name: Ali\nScore: 85\n";
    file.close();
  } else {
    std::cout << "Failed to open file\n";
  }
  return 0;
}
// Output: Creates or overwrites example.txt with content "Name: Ali\nScore: 85\n"

#include <iostream>
#include <fstream>
#include <string>

int main() {
  std::ifstream file("example.txt", std::ios::in);
  std::string line;
  if(file.is_open()) {
    while(std::getline(file, line)) {
      std::cout << line << std::endl;
    }
    file.close();
  } else {
    std::cout << "Failed to open file\n";
  }
  return 0;
}
// Output (assuming example.txt exists):
// Name: Ali
// Score: 85

